type Faq = { q: string; a: string };
type GuideLink = { label: string; href: string };

export type ChemistryGuide = {
  path: string;
  title: string;
  h1: string;
  calculatorName: string;
  topic: string;
  description: string;
  keywords: string;
  primaryKeyword: string;
  formula: string;
  variables: string[];
  formulaWalkthrough: string;
  workedExamples: string[];
  realWorld: string[];
  studentActions: string[];
  commonMistakes: string[];
  connections: GuideLink[];
  connectionDetail: string;
  examContext: string;
  calculationMistake: string;
  labDataContext: string;
  extremeConditions: string;
  industryUse: string;
  baseFaqs: Faq[];
  faqs: Faq[];
  faqHeading: string;
};

type ChemistryGuideInput = Omit<ChemistryGuide, "faqs" | "faqHeading"> & {
  faqHeading?: string;
};

function buildFaqs(guide: ChemistryGuideInput): Faq[] {
  return [
    ...guide.baseFaqs,
    {
      q: "How is this concept tested on AP Chemistry and university general chemistry exams?",
      a: guide.examContext,
    },
    {
      q: "What is the most common calculation error students make with this formula?",
      a: guide.calculationMistake,
    },
    {
      q: "How does this calculation connect to laboratory work and real experimental data?",
      a: guide.labDataContext,
    },
    {
      q: "What happens to this calculation at extreme conditions such as very high or very low temperature, pressure, or concentration?",
      a: guide.extremeConditions,
    },
    {
      q: "When would a professional chemist or chemical engineer use this calculation in industry?",
      a: guide.industryUse,
    },
  ];
}

function makeGuide(input: ChemistryGuideInput): ChemistryGuide {
  return {
    ...input,
    faqHeading: input.faqHeading ?? `Frequently Asked Questions About ${input.topic}`,
    faqs: buildFaqs(input),
  };
}

